package platform

import (
	"context"
	"fmt"
	"strings"
	"testing"
)

// mockResult holds canned data for a mock Browser call.
type mockResult struct {
	names []string
	err   error
}

// mockBrowser dispatches EvalStrings results based on URL substrings
// found in the JS expression.
type mockBrowser struct {
	navigateErr error
	calls       []mockResult // matched in order by URL substring
	urlKeys     []string     // URL substrings to match against
}

func newMockBrowser(mappings map[string]mockResult) *mockBrowser {
	m := &mockBrowser{}
	for k, v := range mappings {
		m.urlKeys = append(m.urlKeys, k)
		m.calls = append(m.calls, v)
	}
	return m
}

func (m *mockBrowser) Navigate(_ context.Context, _ string) error {
	return m.navigateErr
}

func (m *mockBrowser) EvalStrings(_ context.Context, jsExpr string) ([]string, error) {
	for i, key := range m.urlKeys {
		if strings.Contains(jsExpr, key) {
			return m.calls[i].names, m.calls[i].err
		}
	}
	return nil, fmt.Errorf("mock: no match for js expression")
}

